import{_ as d,o as r,c as a,a2 as e}from"./chunks/framework.B72_uj9U.js";const u=JSON.parse('{"title":"食品农业行业审核前文件请求清单（FOOD-AUD-001）","description":"","frontmatter":{},"headers":[],"relativePath":"zh/industry/food/audit-checklist.md","filePath":"zh/industry/food/audit-checklist.md"}'),h={name:"zh/industry/food/audit-checklist.md"};function o(i,t,l,n,b,s){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="食品农业行业审核前文件请求清单-food-aud-001" tabindex="-1">食品农业行业审核前文件请求清单（FOOD-AUD-001） <a class="header-anchor" href="#食品农业行业审核前文件请求清单-food-aud-001" aria-label="Permalink to &quot;食品农业行业审核前文件请求清单（FOOD-AUD-001）&quot;">​</a></h1><blockquote><p><strong>发送时机：</strong> 现场审核前 <strong>4周</strong> 发送给工厂/供应商/农场</p><p><strong>适用范围：</strong> 食品加工厂、农场/种植园、农业原料供应商</p></blockquote><hr><h2 id="模块一-合法经营资质" tabindex="-1">模块一　合法经营资质 <a class="header-anchor" href="#模块一-合法经营资质" aria-label="Permalink to &quot;模块一　合法经营资质&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>1.1</td><td>营业执照/经营许可证</td><td>有效期内</td><td>□</td></tr><tr><td>1.2</td><td>食品生产许可证（SC证）</td><td>中国境内加工厂必须</td><td>□</td></tr><tr><td>1.3</td><td>出口卫生注册证（如适用）</td><td>对欧/美/日出口</td><td>□</td></tr><tr><td>1.4</td><td>环保排污许可证</td><td>有废水排放的加工厂</td><td>□</td></tr><tr><td>1.5</td><td>土地使用权/租赁协议（农场）</td><td>核验土地合法性</td><td>□</td></tr></tbody></table><hr><h2 id="模块二-食品安全管理体系" tabindex="-1">模块二　食品安全管理体系 <a class="header-anchor" href="#模块二-食品安全管理体系" aria-label="Permalink to &quot;模块二　食品安全管理体系&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>2.1</td><td>HACCP计划（最新版）</td><td>含危害分析、CCP及监控记录</td><td>□</td></tr><tr><td>2.2</td><td>ISO 22000 / FSSC 22000 / BRCGS 认证书</td><td>有效期内（如有）</td><td>□</td></tr><tr><td>2.3</td><td>产品检测报告（微生物+农残）</td><td>近6个月，由资质实验室</td><td>□</td></tr><tr><td>2.4</td><td>产品追溯测试记录</td><td>证明可在4小时内追溯批次</td><td>□</td></tr><tr><td>2.5</td><td>食品召回记录</td><td>近5年（含零记录说明）</td><td>□</td></tr><tr><td>2.6</td><td>食品欺诈/掺假风险评估（VACCP）</td><td>如有</td><td>□</td></tr><tr><td>2.7</td><td>过敏原管理程序</td><td>含交叉污染控制</td><td>□</td></tr></tbody></table><hr><h2 id="模块三-劳工-农场-种植园" tabindex="-1">模块三　劳工（农场/种植园） <a class="header-anchor" href="#模块三-劳工-农场-种植园" aria-label="Permalink to &quot;模块三　劳工（农场/种植园）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>3.1</td><td>员工名单（含季节工、外籍工人）</td><td>含年龄、国籍、合同类型</td><td>□</td></tr><tr><td>3.2</td><td>工资发放记录</td><td>近6个月</td><td>□</td></tr><tr><td>3.3</td><td>招募协议样本（含中介协议）</td><td>核验是否收取招募费</td><td>□</td></tr><tr><td>3.4</td><td>外籍/移民劳工工作许可证</td><td>如适用</td><td>□</td></tr><tr><td>3.5</td><td>农药培训记录</td><td>含PPE使用培训</td><td>□</td></tr></tbody></table><hr><h2 id="模块四-eudr合规文件-欧盟毁林法规" tabindex="-1">模块四　EUDR合规文件（欧盟毁林法规） <a class="header-anchor" href="#模块四-eudr合规文件-欧盟毁林法规" aria-label="Permalink to &quot;模块四　EUDR合规文件（欧盟毁林法规）&quot;">​</a></h2><p><em>仅适用于大豆、棕榈油、可可、咖啡、牛肉/皮革、木材、橡胶</em></p><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>4.1</td><td>农场/地块GPS多边形坐标文件</td><td>精确至地块级别</td><td>□</td></tr><tr><td>4.2</td><td>土地转化历史证明（截至2020年12月前）</td><td>卫星图或政府记录</td><td>□</td></tr><tr><td>4.3</td><td>与小农采购的合同及其地块清单</td><td>如涉及小农收购</td><td>□</td></tr><tr><td>4.4</td><td>EUDR尽职调查声明草稿</td><td>如已准备</td><td>□</td></tr></tbody></table><hr><h2 id="模块五-环境" tabindex="-1">模块五　环境 <a class="header-anchor" href="#模块五-环境" aria-label="Permalink to &quot;模块五　环境&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>5.1</td><td>废水检测报告</td><td>近6个月，加工厂适用</td><td>□</td></tr><tr><td>5.2</td><td>农药采购记录及使用登记</td><td>含农药类别、用量</td><td>□</td></tr><tr><td>5.3</td><td>水资源取用许可证</td><td>有取水行为的设施</td><td>□</td></tr><tr><td>5.4</td><td>危险废物处置记录</td><td>农药包装等</td><td>□</td></tr></tbody></table><hr><h2 id="模块六-历史审核" tabindex="-1">模块六　历史审核 <a class="header-anchor" href="#模块六-历史审核" aria-label="Permalink to &quot;模块六　历史审核&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>文件</th><th>要求说明</th><th>已提供</th></tr></thead><tbody><tr><td>6.1</td><td>GlobalG.A.P. / Rainforest Alliance / Fairtrade 认证书</td><td>如有</td><td>□</td></tr><tr><td>6.2</td><td>最近一次第三方审核报告</td><td>12个月内</td><td>□</td></tr><tr><td>6.3</td><td>CAP整改进展</td><td>未关闭项说明</td><td>□</td></tr></tbody></table>',21)])])}const f=d(h,[["render",o]]);export{u as __pageData,f as default};
